import { labelTemplateService } from "./LabelTemplateService";

export async function fetchLabelTemplateList(pageNumber, recordPerPage, selectedKeys ) {
    let response = await labelTemplateService.fetchLabelTemplateList(pageNumber, recordPerPage, selectedKeys );
    return response;
}

export async function saveLabelTemplate(labelTemplateDetails) {
    let response = await labelTemplateService.saveLabelTemplate(labelTemplateDetails);
    return response;
}

export async function saveLabelTemplateScript(templateObj) {
    let response = await labelTemplateService.saveLabelTemplateScript(templateObj);
    return response;
}

export async function saveLabelTemplatePartyMapping(partyCodes, templateCode ) {
    let response = await labelTemplateService.saveLabelTemplatePartyMapping(partyCodes, templateCode);
    return response;
}

export async function activateDeactivateLabelTemplate(templateObj) {
    let response = await labelTemplateService.activateDeactivateLabelTemplate(templateObj);
    return response;
}

export async function deleteLabelTemplate(id) {
    let response = await labelTemplateService.deleteLabelTemplate(id);
    return response;
}

export async function fetchAllPartyMaster() {
    let response = await labelTemplateService.fetchAllPartyMaster();
    return response;
}

export async function fetchLabelPartyMapping() {
    let response = await labelTemplateService.fetchLabelPartyMapping();
    return response;
}